// MARK: - Shared Encoders

nonisolated internal func encodeTopSort(_ value: TopSort, into buffer: inout ByteBuffer) {
    switch value {
    case .bySelf:
        encodeVarint(UInt64(0), into: &buffer)
    case .byTotal:
        encodeVarint(UInt64(1), into: &buffer)
    }
}

nonisolated internal func encodeTimeRange(_ value: TimeRange, into buffer: inout ByteBuffer) {
    encodeVarint(value.startNs, into: &buffer)
    encodeVarint(value.endNs, into: &buffer)
}

nonisolated internal func encodeSymbolRef(_ value: SymbolRef, into buffer: inout ByteBuffer) {
    encodeOption(value.functionName, into: &buffer, encoder: { val, buf in encodeString(val, into: &buf) })
    encodeOption(value.binary, into: &buffer, encoder: { val, buf in encodeString(val, into: &buf) })
}

